import { NextResponse } from 'next/server';
// CORREÇÃO: Adicionado o /src/ conforme pedido
import { pool } from '@/src/lib/db'; 

export async function GET() {
  try {
    // 1. Tenta ligar à base de dados
    const db = await pool.getConnection();
    
    // 2. Pergunta à base de dados: "Que tabelas tens aí?"
    const [rows] = await db.query("SHOW TABLES");
    
    db.release();

    // 3. Devolve a lista de tabelas
    return NextResponse.json({ 
      status: "Sucesso! Ligação efetuada.", 
      tabelas: rows 
    });

  } catch (error: any) {
    // Se der erro, mostra o que aconteceu
    console.error("Erro SQL:", error); // Adicionei um log para veres no terminal também
    return NextResponse.json({ 
      status: "Erro na ligação", 
      erro: error.message 
    }, { status: 500 });
  }
}